inline constexpr usize gl_table_size = sizeof(gl_table) / sizeof(gl_table[0]);

consteval u16
sym_index_of(const char *name) noexcept
{
  for ( u16 i = 0; i < gl_table_size; ++i ) {
    const char *a = gl_table[i].name;
    const char *b = name;
    while ( *a && *a == *b ) {
      ++a;
      ++b;
    }
    if ( *a == 0 && *b == 0 ) return i;
  }
  return u16(-1);
}

